import{_ as e,c as l,o as i,d as t}from"./app.1c033fc5.js";const b='{"title":"\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u0446\u0438\u043A\u043B","description":"","frontmatter":{"title":"\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u0446\u0438\u043A\u043B","subtitle":"\u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043B\u044E\u0431\u044B\u0445 \u0437\u0430\u0434\u0443\u043C\u043E\u043A","date":"2022-03-19T00:00:00.000Z","cover":"cycle.png","color":"#C67E54"},"headers":[{"level":2,"title":"\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B","slug":"\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435-\u043F\u0440\u043E\u0435\u043A\u0442\u044B"},{"level":3,"title":"\u0422\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u0440\u043E\u0435\u043A\u0442","slug":"\u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442"},{"level":3,"title":"\u0410\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439 \u043F\u0440\u043E\u0435\u043A\u0442","slug":"\u0430\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442"},{"level":3,"title":"\u041F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0448\u0430\u0433\u043E\u0432","slug":"\u043F\u043E\u0441n\u0435\u0434\u043E\u0432\u0430\u0442\u0435n\u044C\u043D\u043E\u0441\u0442\u0438-\u0448\u0430\u0433\u043E\u0432"},{"level":3,"title":"\u041F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A","slug":"\u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A"}],"relativePath":"theory/system/projectapp/cycle/index.md"}',a={},r=t('<p>\u0421\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u0439 \u043C\u0438\u0440 \u2014 \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u041E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u044C, \u0438\u0437\u0443\u0447\u0438\u0442\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0441\u0442\u0438, \u043F\u0443\u0441\u0442\u044C \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0435, \u043D\u043E \u0440\u0430\u0437\u0443\u043C\u043D\u044B\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u0432 \u043D\u0430\u0448\u0435\u0439 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043A\u0430\u0436\u0434\u044B\u0439. \u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 \u0441\u0430\u043C\u044B\u0445 \u043F\u0435\u0440\u0432\u044B\u0445 \u043F\u043E\u043F\u044B\u0442\u043E\u043A \u0447\u0442\u043E-\u0442\u043E \u0443\u043B\u0443\u0447\u0448\u0438\u0442\u044C \u0432 \u0441\u0435\u0431\u0435 \u0438\u043B\u0438 \u043C\u0438\u0440\u0435. \u0418, \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044F\u0441\u044C \u0432 \u043D\u0430\u0441, \u043E\u043D\u043E \u043D\u0435\u0440\u0435\u0434\u043A\u043E \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0433\u043B\u0430\u0432\u043D\u044B\u043C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u0440\u0430\u0434\u043E\u0441\u0442\u0438 \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0436\u0438\u0437\u043D\u0438.</p><p>\u0418\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0447\u0435\u043C-\u0442\u043E, \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E \u0438\u0437\u0443\u0447\u0430\u0442\u044C, \u043E\u0431\u0443\u0447\u0430\u0442\u044C\u0441\u044F \u0438 \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B \u0432\u043E \u0432\u0441\u0451 \u0431\u043E\u043B\u0435\u0435 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u043D\u0430\u0447\u0438\u043D\u0430\u043D\u0438\u044F\u0445 \u2014 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0434\u043B\u044F \u043B\u044E\u0434\u0435\u0439. \u041E\u0434\u043D\u0430\u043A\u043E \u043D\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u044D\u0442\u043E\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0434\u0451\u0442 \u0441 \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0439 \u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C\u044E. \u0411\u044B\u0432\u0430\u0435\u0442, \u043D\u0435 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u0440\u0435\u0441\u0443\u0440\u0441\u043E\u0432. \u041D\u0435\u0440\u0435\u0434\u043A\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0441 \u043A\u0430\u0436\u0443\u0449\u0438\u043C\u0438\u0441\u044F \u043D\u0435\u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0438\u043C\u044B\u043C\u0438 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u044F\u043C\u0438 \u0438 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0442\u0440\u0430\u0442\u0438\u0442\u044C \u043D\u0435\u043C\u0430\u043B\u043E \u0441\u0438\u043B, \u0447\u0442\u043E\u0431\u044B \u0438\u0445 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0442\u044C. \u041A\u0442\u043E-\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u0434\u043E\u043B\u0433\u0443 \u0436\u0434\u0430\u0442\u044C \u0432\u0434\u043E\u0445\u043D\u043E\u0432\u0435\u043D\u0438\u044F, \u0430 \u0434\u043B\u044F \u043A\u043E\u0433\u043E-\u0442\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0435\u0433\u043E \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u043C \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C. \u0410 \u0432\u0435\u0434\u044C \u044D\u0442\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E \u043A\u0430\u0436\u0434\u043E\u043C\u0443!</p><p>\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441\u0430\u043C\u044B\u0435 \u043F\u0440\u043E\u0441\u0442\u044B\u0435 \u043E\u0431\u044B\u0434\u0435\u043D\u043D\u044B\u0435 \u0432\u0435\u0449\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u0447\u0430\u0439\u0448\u0438\u0435 \u0438\u0441\u0442\u0438\u043D\u044B \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439. \u0418 \u043E\u043D\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442\u044C \u043D\u0430\u043C \u043F\u043E\u0434\u043B\u0438\u043D\u043D\u0443\u044E \u0440\u0430\u0434\u043E\u0441\u0442\u044C \u0441\u0430\u043C\u043E\u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438. \u041A\u043E\u0433\u0434\u0430 \u0434\u0432\u0438\u0436\u0435\u0448\u044C\u0441\u044F \u043A \u044F\u0441\u043D\u044B\u043C \u0446\u0435\u043B\u044F\u043C, \u0437\u043D\u0430\u0435\u0448\u044C, \u0447\u0442\u043E \u043D\u0443\u0436\u043D\u043E \u0434\u0435\u043B\u0430\u0442\u044C, \u0441\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u0441 \u0442\u0440\u0443\u0434\u043D\u043E\u0441\u0442\u044F\u043C\u0438 \u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0448\u044C \u043D\u0435\u0437\u0430\u043C\u0435\u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u043E\u0431\u0440\u0430\u0442\u043D\u0443\u044E \u0441\u0432\u044F\u0437\u044C, \u043C\u043E\u0436\u0435\u0448\u044C \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043E\u0449\u0443\u0442\u0438\u0442\u044C \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0438 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C. \u0422\u0430\u043A \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043F\u043E\u0442\u043E\u043A\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u0435\u043B\u0430\u0435\u0442 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0434\u0430\u0436\u0435 \u0431\u043E\u043B\u0435\u0435 \u0446\u0435\u043D\u043D\u044B\u043C, \u0447\u0435\u043C \u0435\u0433\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B.</p><h2 id="\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435-\u043F\u0440\u043E\u0435\u043A\u0442\u044B" tabindex="-1">\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B <a class="header-anchor" href="#\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0435-\u043F\u0440\u043E\u0435\u043A\u0442\u044B" aria-hidden="true">#</a></h2><ul><li>\u0418\u043D\u0436\u0435\u043D\u0435\u0440\u043D\u044B\u0439</li><li>\u0425\u0443\u0434\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439</li><li>\u041C\u0443\u0437\u044B\u043A\u0430\u043B\u044C\u043D\u044B\u0439</li><li>\u041D\u0430\u0443\u0447\u043D\u044B\u0439</li><li>\u041F\u0435\u0434\u0430\u0433\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0439</li><li>\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439</li><li>\u0418\u0437\u043E\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0439</li><li>\u041A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u044B\u0439</li><li>\u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0442\u043E\u0440\u0441\u043A\u0438\u0439</li><li>\u041F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0439</li><li>\u0424\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0439</li><li>\u0418\u0433\u0440\u043E\u0432\u043E\u0439</li></ul><blockquote><h3 id="\u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442" tabindex="-1">\u0422\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 <a class="header-anchor" href="#\u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442" aria-hidden="true">#</a></h3><p>\u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0438\u0437\u0434\u0435\u043B\u0438\u044F \u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0433\u043E \u0434\u043B\u044F \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447.</p></blockquote><blockquote><h3 id="\u0430\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442" tabindex="-1">\u0410\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 <a class="header-anchor" href="#\u0430\u0432\u0442\u043E\u0440\u0441\u043A\u0438\u0439-\u043F\u0440\u043E\u0435\u043A\u0442" aria-hidden="true">#</a></h3><p>\u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0430\u0432\u0442\u043E\u0440\u0441\u043A\u043E\u0433\u043E \u0437\u0430\u043C\u044B\u0441\u043B\u0430 \u0432 \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u043E\u043C \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u0438.</p></blockquote><p>\u041A\u0430\u0436\u0434\u044B\u0439, \u043A\u0442\u043E \u0445\u043E\u0442\u044C \u0440\u0430\u0437 \u0432\u043E\u043F\u043B\u043E\u0442\u0438\u043B \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043D\u043E\u0435 \u2014 \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u043B \u043F\u0440\u043E\u0435\u043A\u0442. \u041A\u043B\u044E\u0447\u0435\u0432\u0430\u044F \u0447\u0435\u0440\u0442\u0430 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u2014 \u0435\u0433\u043E \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C. \u042F\u0441\u043D\u043E\u0441\u0442\u044C \u0446\u0435\u043B\u0435\u0439 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0445 \u0442\u043E\u0447\u043D\u043E\u0441\u0442\u044C\u044E, \u0438\u0437\u043C\u0435\u0440\u0438\u043C\u043E\u0441\u0442\u044C\u044E, \u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E\u0441\u0442\u044C\u044E, \u044D\u043A\u043E\u043B\u043E\u0433\u0438\u0447\u043D\u043E\u0441\u0442\u044C\u044E \u0438 \u0441\u0432\u043E\u0435\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E. \u041E \u0437\u0430\u043C\u043A\u0430\u0445 \u0432 \u043E\u0431\u043B\u0430\u043A\u0430\u0445 \u043C\u043E\u0436\u043D\u043E \u0434\u043E\u043B\u0433\u043E \u043C\u0435\u0447\u0442\u0430\u0442\u044C \u0438 \u043D\u0435 \u0438\u043C\u0435\u0442\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0434\u0432\u0438\u043D\u0443\u0442\u044C\u0441\u044F \u043D\u0430\u0432\u0441\u0442\u0440\u0435\u0447\u0443 \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043D\u043E\u043C\u0443. \u041D\u043E \u0441\u0442\u043E\u0438\u0442 \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 \u043F\u043E\u0442\u043E\u0447\u043D\u0435\u0435, \u043A\u0430\u043A \u0441\u0440\u0430\u0437\u0443 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043D\u043E\u0432\u044B\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B\u0435 \u043F\u043E\u043C\u043E\u0447\u044C \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044C\u0441\u044F \u0432 \u0432\u044B\u0431\u0440\u0430\u043D\u043D\u043E\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438. \u0422\u0430\u043A \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435.</p><p>\u0417\u0430\u0434\u0443\u043C\u0430\u0442\u044C \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u0439 \u043F\u0440\u043E\u0435\u043A\u0442 \u0436\u0438\u0437\u043D\u0438 \u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0430\u0442\u044C \u0435\u0433\u043E \u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u044F\u043C\u0438 \u2014 \u0433\u0435\u0440\u043E\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u043E\u0441\u0442\u0443\u043F\u043E\u043A, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u0434\u0430\u043B\u0435\u043A\u043E \u043D\u0435 \u043A\u0430\u0436\u0434\u044B\u0439. \u041D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0434\u0430\u0436\u0435 \u0441\u0430\u043C\u044B\u0445 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0446\u0435\u043B\u0435\u0439 \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0431\u0438\u0442\u044C \u043D\u0430 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u044B\u0435 \u044D\u0442\u0430\u043F\u044B, \u0434\u0430\u0451\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443 \u0443\u0432\u0435\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432 \u0437\u043D\u0430\u0447\u0438\u043C\u043E\u0441\u0442\u0438 \u043F\u0440\u0438\u043B\u0430\u0433\u0430\u0435\u043C\u044B\u0445 \u0443\u0441\u0438\u043B\u0438\u0439. \u041E\u0434\u043D\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u0440\u0430\u0431\u043E\u0442\u044B \u043D\u0430\u0434 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0438 \u0432 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0437\u0430\u0434\u0430\u0447\u043A\u0435 \u043D\u0430 \u043F\u043E\u043B\u0447\u0430\u0441\u0430 \u0438 \u0432 \u043A\u0440\u0443\u043F\u043D\u043E\u043C \u043D\u0430\u0447\u0438\u043D\u0430\u043D\u0438\u0438, \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u043C\u043E\u043C \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u043B\u044E\u0434\u0435\u0439 \u043C\u0435\u0441\u044F\u0446\u0430\u043C\u0438. \u042D\u0442\u043E \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u0444\u0440\u0430\u043A\u0442\u0430\u043B, \u0433\u0434\u0435 \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C \u043A\u0430\u043A \u043F\u0440\u043E\u0435\u043A\u0442 \u0445\u043E\u0442\u044C \u043E\u0434\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u043E\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0445\u043E\u0442\u044C \u0432\u0441\u044E \u0441\u0432\u043E\u044E \u0436\u0438\u0437\u043D\u044C. \u0412\u0430\u0436\u043D\u043E \u043D\u0430\u0439\u0442\u0438 \u0432 \u044D\u0442\u043E\u0439 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u0438 \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043C\u0430\u0441\u0448\u0442\u0430\u0431, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0438\u0439 \u043A\u043E\u043C\u0444\u043E\u0440\u0442\u043D\u043E \u0438 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0438 \u0443\u0441\u0438\u043B\u0438\u044F.</p><p>\u041B\u044E\u0431\u043E\u0435 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u0435\u0442 \u043F\u0440\u043E\u0435\u043A\u0442\u0430\u043C\u0438. \u041E\u0442 \u0435\u0434\u0432\u0430 \u0443\u043B\u043E\u0432\u0438\u043C\u043E\u0439 \u0438\u0434\u0435\u0438 \u0438 \u0433\u0440\u0443\u0431\u044B\u0445 \u043D\u0430\u0431\u0440\u043E\u0441\u043A\u043E\u0432 \u0434\u043E \u043F\u043E\u043B\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0438 \u0445\u0443\u0434\u043E\u0436\u043D\u0438\u043A \u0438 \u0441\u0442\u043E\u043B\u044F\u0440, \u0438 \u043A\u0435\u0440\u0430\u043C\u0438\u0441\u0442 \u0438 \u043F\u043E\u044D\u0442. \u041E\u0431\u044B\u0447\u043D\u043E \u044D\u0442\u043E \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0441 \u043E\u043F\u044B\u0442\u043E\u043C \u0438 \u043C\u043D\u043E\u0433\u0438\u0435 \u0434\u0430\u0436\u0435 \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u0434\u043E \u043A\u043E\u043D\u0446\u0430 \u0441\u0432\u043E\u0438 \u043C\u0435\u0442\u043E\u0434\u0438\u043A\u0438 \u0440\u0430\u0431\u043E\u0442\u044B. \u041E\u0434\u043D\u0430\u043A\u043E \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 \u043D\u0435 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u0442\u044C \u0438 \u043F\u043E\u0441\u0442\u0443\u043F\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u043A \u043D\u0430\u043C\u0435\u0447\u0435\u043D\u043D\u044B\u043C \u0446\u0435\u043B\u044F\u043C. \u0410 \u043F\u043E \u043C\u0435\u0440\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0446\u0438\u043A\u043B\u0430, \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043E\u043C \u043F\u0440\u043E\u0445\u043E\u0434\u044F \u043A\u043E\u0442\u043E\u0440\u044B\u0439, \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0448\u044C \u0441\u0435\u0431\u044F \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u043C \u0432 \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u043C \u043C\u0438\u0440\u0435. \u0418 \u044D\u0442\u043E\u0442 \u0446\u0438\u043A\u043B \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043B\u0438\u0448\u044C \u0432\u0438\u0442\u043A\u043E\u043C \u0432 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0441\u043F\u0438\u0440\u0430\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0438 \u0441\u0430\u043C\u043E\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F.</p><h3 id="\u043F\u043E\u0441n\u0435\u0434\u043E\u0432\u0430\u0442\u0435n\u044C\u043D\u043E\u0441\u0442\u0438-\u0448\u0430\u0433\u043E\u0432" tabindex="-1">\u041F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0448\u0430\u0433\u043E\u0432 <a class="header-anchor" href="#\u043F\u043E\u0441n\u0435\u0434\u043E\u0432\u0430\u0442\u0435n\u044C\u043D\u043E\u0441\u0442\u0438-\u0448\u0430\u0433\u043E\u0432" aria-hidden="true">#</a></h3><p>\u041B\u044E\u0431\u043E\u0439 \u043F\u0443\u0442\u044C \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0448\u0430\u0433\u043E\u0432 \u0442\u043E\u0439 \u0438\u043B\u0438 \u0438\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B. \u0418\u0445 \u043C\u043E\u0436\u043D\u043E \u0433\u0440\u0443\u043F\u043F\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438 \u0434\u0435\u043B\u0438\u0442\u044C \u043D\u0430 \u043B\u044E\u0431\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0446\u0435\u043F\u043E\u0447\u0435\u043A \u0438 \u0433\u0440\u0443\u043F\u043F. \u041A \u0442\u043E\u043C\u0443 \u0436\u0435 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u043A \u043F\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u0446\u0435\u043B\u0438 \u0434\u0430\u043B\u0435\u043A\u043E \u043D\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u044F\u043C\u043E\u043B\u0438\u043D\u0435\u0439\u043D\u043E. \u0412 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043F\u0440\u043E\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438\u0434\u0435\u0438 \u0438 \u0435\u0451 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043D\u043E\u0432\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B, \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0438 \u0432\u044B\u0431\u043E\u0440\u044B. \u041D\u043E \u043C\u043E\u0436\u043D\u043E \u0432\u044B\u0434\u0435\u043B\u0438\u0442\u044C \u0440\u044F\u0434 \u043E\u0431\u0449\u0438\u0445 \u0437\u0430\u043A\u043E\u043D\u043E\u043C\u0435\u0440\u043D\u043E\u0441\u0442\u0435\u0439 \u0438 \u0440\u0430\u0437\u043C\u0435\u0442\u0438\u0442\u044C \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0434\u043E\u0431\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u044B \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043D\u0430 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u043C \u043F\u0443\u0442\u0438.</p><p>\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u043A\u0440\u0443\u043F\u043D\u043E\u043C \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0435 \u0443 \u043D\u0430\u0441 \u0435\u0441\u0442\u044C \u0434\u0432\u0430 \u043F\u0443\u043D\u043A\u0442\u0430 \u2013 \u043E\u0442\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u0441\u044F \u043E\u0442 \u0438\u0434\u0435\u0438 \u0438 \u043F\u0440\u0438\u0431\u044B\u0432\u0430\u0435\u043C \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442. \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u0431\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E \u0432\u0441\u0435 \u043F\u043E\u0434 \u0440\u0443\u043A\u043E\u0439, \u0440\u0443\u043A \u0438 \u0437\u043D\u0430\u043D\u0438\u0439 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u0438 \u043A\u0430\u043A \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0433\u043E\u043B\u043E\u0432\u0435 \u0447\u0442\u043E-\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u2013 \u0441\u0440\u0430\u0437\u0443 \u0431\u0435\u0440\u0435\u0448\u044C \u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0430\u0435\u0448\u044C \u044D\u0442\u043E \u0432 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0435. \u0420\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 \u0432 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u0438\u0434\u0435\u0438 \u043D\u0430\u043F\u0440\u044F\u043C\u0443\u044E \u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u0443\u044E \u0444\u043E\u0440\u043C\u0443. \u0422\u0430\u043A \u043C\u044B \u043D\u0430\u0445\u043E\u0434\u0438\u043C \u0434\u0432\u0430 \u043F\u043E\u043B\u044E\u0441\u0430 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430: \u043F\u0430\u0440\u0443 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0438.</p><h3 id="\u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A" tabindex="-1">\u041F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A <a class="header-anchor" href="#\u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u043A" aria-hidden="true">#</a></h3><p>\u041D\u0435 \u0432\u0430\u0436\u043D\u043E, \u0447\u0442\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0440\u0430\u0431\u043E\u0442\u044B \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043E\u043C \u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F \u0433\u0434\u0435-\u0442\u043E \u043F\u043E\u0437\u0430\u0434\u0438, \u044D\u0442\u043E \u043B\u0438\u0448\u044C \u043F\u0440\u0438\u0437\u043D\u0430\u043A \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0432\u043F\u0435\u0440\u0435\u0434 \u043F\u043E \u043F\u0443\u0442\u0438. \u0423\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u0440\u0430\u0441\u0441\u043B\u0430\u0431\u043B\u0435\u043D\u0438\u0435, \u043F\u0440\u0430\u0437\u0434\u043D\u043E\u0441\u0442\u044C \u2014 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0439 \u0448\u0442\u0438\u043B\u044C \u0443\u043C\u0430, \u043A\u043E\u0433\u0434\u0430 \u0443\u0442\u0438\u0445\u0430\u0435\u0442 \u0431\u0443\u0440\u044F \u043C\u044B\u0441\u043B\u0435\u0439 \u0438 \u0434\u0435\u043B. \u0412 \u044D\u0442\u043E\u0439 \u0442\u0438\u0448\u0438\u043D\u0435 \u043C\u043E\u0436\u043D\u043E \u0443\u043B\u043E\u0432\u0438\u0442\u044C \u0434\u0430\u0436\u0435 \u0441\u0430\u043C\u044B\u0435 \u0442\u043E\u043D\u043A\u0438\u0435 \u0438\u0434\u0435\u0438 \u0438 \u0441\u043C\u044B\u0441\u043B\u044B.</p><p>\u0410 \u043F\u043E\u0441\u043B\u0435 \u043E\u0441\u0432\u0435\u0436\u0430\u044E\u0449\u0435\u0433\u043E \u043F\u0435\u0440\u0435\u0440\u044B\u0432\u0430 \u043B\u0435\u0433\u043A\u043E \u0431\u0440\u0430\u0442\u044C\u0441\u044F \u0437\u0430 \u043D\u043E\u0432\u044B\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u044B.</p><blockquote><p>\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u0437\u0430\u043F\u043E\u043B\u043D\u0438\u0442 \u0432 \u043B\u044E\u0431\u044B\u0435 \u0437\u0430\u0434\u0430\u043D\u043D\u044B\u0435 \u0440\u0430\u043C\u043A\u0438, \u043D\u043E \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u043E \u2014 \u044D\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u044B\u0445\u043E\u0434 \u0437\u0430 \u0433\u0440\u0430\u043D\u0438\u0446\u044B \u043F\u0440\u0430\u0432\u0438\u043B \u0438 \u043D\u043E\u0440\u043C. \u041D\u0435\u0440\u0430\u0437\u0440\u044B\u0432\u043D\u044B\u0439 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043C\u043E\u0436\u043D\u043E \u0434\u0435\u043B\u0438\u0442\u044C \u043D\u0430 \u043B\u044E\u0431\u043E\u0435 \u0447\u0438\u0441\u043B\u043E \u044D\u0442\u0430\u043F\u043E\u0432, \u0448\u0430\u0433\u043E\u0432 \u0438 \u0444\u0430\u0437, \u043F\u044B\u0442\u0430\u044F\u0441\u044C \u043D\u0430\u0439\u0442\u0438 \u0432 \u043D\u0451\u043C \u0447\u0451\u0442\u043A\u0438\u0439 \u0440\u0438\u0442\u043C \u0438 \u043F\u043E\u0440\u044F\u0434\u043E\u043A, \u043D\u043E \u0441\u0442\u043E\u0438\u0442 \u043F\u043E\u043C\u043D\u0438\u0442\u044C \u043F\u0440\u0438 \u044D\u0442\u043E\u043C, \u0447\u0442\u043E \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u0439 \u0434\u043B\u044F \u0441\u0430\u043C\u043E\u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043D\u0435\u0442.</p></blockquote>',17),o=[r];function c(d,n,p,s,h,_){return i(),l("div",null,o)}var f=e(a,[["render",c]]);export{b as __pageData,f as default};
